INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Heatmaps$q$, $q$Aggregate click, scroll, and area heatmaps show where visitors focus attention across a page.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Session recordings$q$, $q$Anonymized replays of individual visitor sessions let teams watch exactly how a user navigated a page.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Rage click and dead click detection$q$, $q$Automatic flags for repeated rapid clicking or clicks on non-interactive elements highlight likely friction points.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Clarity Copilot$q$, $q$An AI assistant that answers natural-language questions about site behavior directly from the dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Custom tags and segments$q$, $q$Filter recordings and heatmaps by URL, device, browser, or custom JavaScript-triggered events.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Google Analytics integration$q$, $q$Connects with Google Analytics and Google Analytics 360 to cross-reference recordings against existing GA segments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Platform one-click installs$q$, $q$Native integrations for WordPress, Shopify, Shopify Plus, Wix, Squarespace, and WooCommerce simplify setup.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Unlimited free usage$q$, $q$No caps on sites, team members, or monthly tracked sessions under the single free tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Completely free with no paid tier or feature paywall$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$No limits on websites, team seats, or session volume$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Fast, simple setup with one-click integrations for major platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$AI-powered Clarity Copilot speeds up finding friction points$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Automatic frustration signals (rage clicks, dead clicks) surface UX issues without manual review$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Fewer advanced segmentation and reporting options than paid competitors like FullStory$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$No dedicated customer support channel beyond community and documentation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Interface and filtering are simpler than more mature paid session-recording tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Data retention windows are shorter than some enterprise-grade paid platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Aggregated anonymized data is used by Microsoft to improve its own models, which some privacy-conscious teams may want to review$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Is Microsoft Clarity really free?$q$, $q$Yes. Clarity has a single free tier with no Pro, Business, or Enterprise plan, and no limits on sites, team members, or monthly sessions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$When was Microsoft Clarity launched?$q$, $q$Clarity launched publicly on October 28, 2020, after starting as an internal Microsoft project around 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Does Microsoft Clarity work with Google Analytics?$q$, $q$Yes, Clarity integrates with Google Analytics and Google Analytics 360, allowing teams to cross-reference session recordings with existing GA segments.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$What is Clarity Copilot?$q$, $q$Clarity Copilot is a built-in AI assistant that lets users ask natural-language questions about site behavior, such as the top friction point on a page, and returns a generated answer.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Which platforms does Microsoft Clarity support out of the box?$q$, $q$Clarity offers one-click installation for WordPress, Shopify, Shopify Plus, Wix, Squarespace, and WooCommerce, plus manual script or Google Tag Manager installation for any other site.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$How does Microsoft make money from a free product like Clarity?$q$, $q$Microsoft uses the anonymized, aggregated behavioral data Clarity collects to improve its own machine learning models and understand digital usage trends, rather than charging for the product directly.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$UX and conversion optimization$q$, $q$Product and marketing teams use heatmaps and session recordings to identify where visitors drop off or get confused on key pages like checkout or signup flows.$q$, $q$UX researchers and conversion rate optimization teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$E-commerce store troubleshooting$q$, $q$Shopify and WooCommerce store owners install Clarity to watch real shopping sessions and diagnose why visitors abandon carts.$q$, $q$Small business and e-commerce owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$SEO and content performance review$q$, $q$SEO practitioners pair Clarity with Google Search Console data to see how visitors from organic search actually engage with landing pages.$q$, $q$SEO and content marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited sites","Unlimited team members","Heatmaps and session recordings","Rage click and dead click detection","Clarity Copilot AI insights","Custom tags and segments","Google Analytics integration"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Clarity is a free website analytics tool that captures how real visitors interact with a page. It began as an internal Microsoft project studying user behavior on properties like Bing before its public release on October 28, 2020, and it has remained free with no paid tier since launch.$q$, $q$Unlike traditional analytics tools that report pageviews and conversion funnels, Clarity focuses on qualitative behavior: heatmaps that show where people click and scroll, and session recordings that replay individual visits. It is designed to sit alongside Google Analytics rather than replace it, filling in the 'why' behind the numbers a traffic dashboard already shows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Clarity's core features are heatmaps (click, scroll, and area heatmaps aggregated across sessions), session recordings (anonymized replays of individual visitor sessions), and automatic frustration signals like rage clicks, dead clicks, and excessive scrolling that flag likely UX problems without manual review.$q$, $q$Clarity Copilot, an AI assistant built into the dashboard, lets users ask plain-language questions about site behavior and receive a generated summary instead of manually filtering recordings. Clarity also supports custom tags and segments for filtering sessions by URL, device, browser, or custom JavaScript-triggered events, and it connects to Google Analytics and Google Analytics 360 so recordings can be cross-referenced against existing GA segments. One-click installation is available for WordPress, Shopify, Shopify Plus, Wix, Squarespace, and WooCommerce, in addition to manual script or Google Tag Manager installation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b89d9029-ae3f-4881-beeb-41c427d2ace5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Microsoft Clarity has a single pricing tier: free. There are no Pro, Business, or Enterprise plans, no caps on the number of sites, team members, or monthly sessions tracked, and every feature, including heatmaps, session recordings, Clarity Copilot, and custom tags, is available to every account at no cost.$q$, $q$Microsoft sustains Clarity as a free product because the anonymized, aggregated behavioral data it collects feeds Microsoft's own machine learning research and product decisions, rather than generating direct subscription revenue. This makes Clarity an outlier among session-recording tools, most of which (Hotjar, FullStory, Crazy Egg) gate recording volume, data retention, or advanced filtering behind paid plans.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Conversational chat$q$, $q$Ask questions, draft text, brainstorm, and get summarized answers in natural language.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Web-grounded answers$q$, $q$Copilot can search the live web to ground responses in current information rather than relying only on training data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Image generation$q$, $q$Generates images from text prompts using OpenAI image models.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Voice mode$q$, $q$Supports spoken, conversational interaction instead of typed prompts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Copilot Vision$q$, $q$Can analyze on-screen content or a camera feed to answer questions about what it sees.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Selectable models$q$, $q$Lets users choose between Microsoft's default model and alternatives, including Anthropic's Claude, for specific tasks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Windows and Edge integration$q$, $q$Built natively into Windows, Bing, and Microsoft Edge for access without a separate app.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Agentic task mode$q$, $q$A multi-step agentic mode can carry out longer tasks across a user's data rather than answering one prompt at a time.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Free tier available to anyone with a Microsoft account$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Deep native integration into Windows, Bing, and Edge without installing a separate app$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Combines chat, image generation, voice, and web search in one assistant$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Access to multiple underlying AI models, including Claude, in one interface$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Frequent feature updates tied to Microsoft's broader AI roadmap$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Naming overlaps with Microsoft 365 Copilot and GitHub Copilot cause frequent user confusion$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Standalone Copilot Pro was discontinued, pushing consumers toward bundled Microsoft 365 subscriptions for advanced features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Response quality and available models can vary by region and account type$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Some advanced features require a Microsoft 365 subscription rather than being free$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Enterprise-grade data controls require the separate Microsoft 365 Copilot product, not the consumer version$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Is Microsoft Copilot free to use?$q$, $q$Yes, the core Copilot experience at copilot.microsoft.com is free with a Microsoft account, including chat, web-grounded answers, and limited image generation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$How is Microsoft Copilot different from Microsoft 365 Copilot?$q$, $q$Microsoft Copilot is a general-purpose consumer chat assistant, while Microsoft 365 Copilot is a separate, separately priced product embedded inside Word, Excel, PowerPoint, Outlook, and Teams for enterprise productivity tasks.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Is Microsoft Copilot the same as GitHub Copilot?$q$, $q$No. GitHub Copilot is a code-completion assistant for developers inside code editors, while Microsoft Copilot is a general chat assistant for everyday tasks and questions.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$What happened to Copilot Pro?$q$, $q$Microsoft retired the standalone $20 per month Copilot Pro subscription in late 2025; existing subscribers can keep using it until August 1, 2026, after which advanced features move into Microsoft 365 Personal, Family, and Premium plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$What AI models power Microsoft Copilot?$q$, $q$Copilot is built primarily on OpenAI's GPT model family, and in 2026 Microsoft added the option to select alternate models, including Anthropic's Claude, within Copilot Chat.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$What was Microsoft Copilot called before it was Copilot?$q$, $q$It started as Bing Chat, launched February 7, 2023 as part of the redesigned Bing search engine, and was renamed Copilot at Microsoft Ignite in November 2023.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Everyday question answering and research$q$, $q$Consumers use the free chat interface for quick answers, summaries, and web-grounded research without needing a separate AI account.$q$, $q$General consumers and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$In-OS assistance for Windows users$q$, $q$Windows users access Copilot directly from the taskbar for tasks like drafting text, adjusting settings, or answering questions without opening a browser.$q$, $q$Windows PC users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Visual and voice-driven tasks$q$, $q$Users leverage Copilot Vision and voice mode to get help with on-screen content or hands-free conversations, such as troubleshooting an app or discussing a document aloud.$q$, $q$Mobile and accessibility-focused users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Conversational chat","Web-grounded answers","Limited image generation","Basic voice mode"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Microsoft 365 Personal$q$, $q$$9.99/month$q$, $q$Monthly$q$, NULL, $q$["Copilot features integrated into personal Microsoft 365 apps","Increased AI credit allowance","Cloud storage and Office apps"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$Microsoft 365 Premium$q$, $q$$19.99/month$q$, $q$Monthly$q$, NULL, $q$["Full consumer AI feature set (successor to Copilot Pro)","Priority access to latest models","Deeper Microsoft 365 app integration"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Copilot is the company's consumer AI chat assistant, reachable directly at copilot.microsoft.com and built into Windows, Bing, and Microsoft Edge. It grew out of Bing Chat, the GPT-4-powered chatbot Microsoft added to Bing search on February 7, 2023, and was unified under the Copilot brand in late 2023.$q$, $q$Copilot is separate from Microsoft 365 Copilot (the enterprise productivity assistant embedded in Word, Excel, and Teams) and GitHub Copilot (a developer coding assistant), even though all three share the Copilot name and underlying AI technology.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core experience is a conversational chat interface that can answer questions, draft and summarize text, and browse the live web to ground answers in current information. Copilot also generates images from text prompts, offers a voice mode for spoken conversation, and includes Copilot Vision, which can analyze on-screen content or a camera feed to answer questions about what it sees.$q$, $q$In 2026, Microsoft added the ability to select alternate underlying models inside Copilot Chat, including Anthropic's Claude, for tasks like document understanding and structured content generation, alongside its default OpenAI-based models. A newer agentic mode, sometimes referred to as Cowork, can carry out multi-step tasks across a user's data rather than answering a single prompt at a time.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8439de35-62ee-4d9e-bf6a-d659a4bed51b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Microsoft Copilot experience at copilot.microsoft.com is free to anyone with a Microsoft account, including standard chat, web-grounded answers, and limited image generation. Microsoft previously sold a standalone Copilot Pro subscription at $20 per month for individuals wanting faster responses and deeper app integration, but retired it in late 2025 in favor of folding those capabilities into Microsoft 365 subscription tiers.$q$, $q$Consumers who want the advanced features that used to require Copilot Pro can now get them through Microsoft 365 Personal, Family, or Premium plans, with Premium (around $19.99 per month) offering the fullest AI feature set. Separately, Microsoft 365 Copilot for business and enterprise customers is priced at roughly $30 per user per month as an add-on to a qualifying Microsoft 365 plan, and is a distinct product from the consumer Copilot covered here.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Text-to-design generation$q$, $q$Describe a design concept and Designer generates a complete layout with images, text, and color scheme.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$DALL-E 3 image generation$q$, $q$Creates original images from text prompts using OpenAI's DALL-E 3 model.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Restyle Image$q$, $q$Reimagines an uploaded photo in a new AI-generated artistic style.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Background removal and replacement$q$, $q$Automatically isolates subjects and swaps backgrounds for product or portrait photography.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Object erase and auto-crop$q$, $q$Removes unwanted elements from an image and automatically crops to standard design dimensions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$AI caption and copy suggestions$q$, $q$Generates text suggestions to pair with visuals for social posts and marketing materials.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Microsoft 365 app integration$q$, $q$Generation and editing tools are embedded directly inside Microsoft Photos, Word, and PowerPoint.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Template library$q$, $q$Pre-built templates for social posts, presentation slides, flyers, and invitations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Free tier accessible to any Microsoft account holder$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$DALL-E 3 image generation built directly into the design workflow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Integrates natively into PowerPoint, Word, and Microsoft Photos$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$AI editing tools (Restyle, background removal, object erase) go beyond basic template editing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Simple, prompt-based workflow lowers the skill barrier for non-designers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Free tier credit allowance (around 15/month) is limiting for frequent use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Full credit benefits require a paid Microsoft 365 subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Design customization is less deep than long-established tools like Canva or Adobe Express$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Smaller third-party template and asset marketplace compared to Canva$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$AI-generated layouts sometimes need manual cleanup for brand-specific requirements$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Is Microsoft Designer free?$q$, $q$Yes, the core app is free with any Microsoft account and includes a monthly allowance of around 15 AI generation credits; Microsoft 365 subscriptions raise that allowance further.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$What AI model does Microsoft Designer use for images?$q$, $q$Designer currently uses OpenAI's DALL-E 3, an upgrade from the DALL-E 2 model it launched with in 2022.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$When did Microsoft Designer launch?$q$, $q$It launched in public preview on October 12, 2022, and reached general availability in July 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Is Microsoft Designer a Canva alternative?$q$, $q$Yes, it is widely positioned as Microsoft's answer to Canva, focused on AI-generated layouts rather than manual drag-and-drop design.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Does Microsoft Designer work inside PowerPoint and Word?$q$, $q$Yes, Designer's image generation and editing tools are integrated directly into Microsoft Photos, Word, and PowerPoint, in addition to the standalone web and mobile app.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Do I need a Microsoft 365 subscription to use Designer?$q$, $q$No, the app is usable for free with a Microsoft account, but a Microsoft 365 Personal, Family, or Premium subscription increases the monthly AI credit allowance.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Social media content creation$q$, $q$Marketers and creators generate on-brand social posts and stories quickly using text prompts instead of manual layout work.$q$, $q$Social media managers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Presentation slide design$q$, $q$Users generate polished visuals and layouts for PowerPoint presentations directly within the app.$q$, $q$Students and business professionals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Marketing materials for small businesses$q$, $q$Small businesses create flyers, invitations, and promotional graphics without hiring a designer or learning complex design software.$q$, $q$Small business owners and freelancers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Around 15 AI generation credits per month","Access to templates and editing tools","Web and mobile app access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Microsoft 365 Personal$q$, $q$$9.99/month$q$, $q$Monthly$q$, NULL, $q$["Increased AI credit allowance","Copilot integration across personal Microsoft 365 apps"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$Microsoft 365 Premium$q$, $q$$19.99/month$q$, $q$Monthly$q$, NULL, $q$["Largest AI credit allowance","Full Copilot and AI feature set across Microsoft 365 apps"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Designer is an AI graphic design tool that generates full layouts, images, and copy suggestions from a text description. It launched in public preview on October 12, 2022, alongside Microsoft's push to integrate OpenAI's DALL-E 2 into its consumer products, and reached general availability in July 2024.$q$, $q$Positioned as a Canva alternative, Designer is built to work inside the Microsoft ecosystem: it is a standalone web and mobile app, but its generation and editing tools also appear inside Microsoft Photos, Word, and PowerPoint.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Designer's core workflow starts with a text prompt: users describe a design concept and the app generates layouts with images, text placement, color palettes, and decorative elements already assembled. Image generation runs on DALL-E 3, an upgrade from the original DALL-E 2 integration at launch.$q$, $q$Editing tools include background removal and replacement, object erase, auto-crop, and Restyle Image, which applies a new artistic style to an existing photo. Designer also suggests AI-generated captions and copy to accompany visuals, and it supports templates for common formats like social posts, presentation slides, flyers, and invitations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3f7e295f-cbc2-49fa-af99-9d4aa080d1b3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Microsoft Designer's core app is free to any Microsoft account holder and includes a monthly allowance of around 15 AI generation credits. This is enough for light, occasional design work but limits users who need to generate many images in a month.$q$, $q$A Microsoft 365 subscription increases the monthly credit allowance to roughly 4x the free amount and adds broader Copilot integration across Microsoft 365 apps. The relevant tiers are Microsoft 365 Personal (around $9.99/month), Family (around $12.99/month), and Premium (around $19.99/month), with Premium offering the largest credit pool and most complete AI feature set.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Single sign-on (SSO)$q$, $q$Centralized authentication across Microsoft 365, Azure, and thousands of third-party SaaS apps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Multi-factor authentication$q$, $q$Adds a second verification step, including Microsoft Authenticator and FIDO2 security keys, to sign-in.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Conditional Access$q$, $q$Policies that grant or restrict access based on device, location, and calculated sign-in risk.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Identity Protection$q$, $q$Machine-learning-based risk detection on sign-ins and user accounts, feeding risk scores into access policies.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Privileged Identity Management (PIM)$q$, $q$Just-in-time elevation of administrative access instead of granting standing admin rights.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Self-service password reset$q$, $q$Lets users reset their own passwords without IT involvement, including in hybrid on-premises/cloud setups.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$B2B collaboration$q$, $q$Invites external partners into a tenant for secure collaboration, supported at up to 50,000 monthly active users on the free tier.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Access reviews$q$, $q$Periodic recertification workflows to confirm users still need the access they hold.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Free tier covers SSO, MFA, and B2B collaboration for smaller organizations$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Deep native integration with Microsoft 365, Azure, and Windows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Often already included via existing Microsoft 365 E3 or E5 licensing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Identity Protection and PIM provide strong zero-trust security controls at the P2 tier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Supports thousands of pre-built third-party SaaS app integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Advanced security features (Conditional Access, PIM, Identity Protection) require paid P1 or P2 licensing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Licensing tiers and bundling with Microsoft 365 plans can be confusing to price out$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Prices increased in 2026, raising the cost of P1 and P2 tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Feature overlap and naming changes from the Azure AD rebrand can confuse long-time admins$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Full capability set is deepest for organizations already standardized on Microsoft 365 and Azure$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Is Microsoft Entra ID the same as Azure Active Directory?$q$, $q$Yes, Microsoft renamed Azure Active Directory to Microsoft Entra ID starting July 11, 2023; Microsoft stated that pricing and functionality were unchanged, only the name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Is there a free version of Microsoft Entra ID?$q$, $q$Yes, Entra ID Free is included with any Microsoft online business service and supports up to 500,000 directory objects and SSO for up to 10 cloud apps per user.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$What is the difference between Entra ID P1 and P2?$q$, $q$P1 adds Conditional Access and hybrid self-service password reset; P2 adds everything in P1 plus Identity Protection and Privileged Identity Management (PIM).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$How much does Microsoft Entra ID cost?$q$, $q$As of 2026, P1 costs roughly $6 to $7 per user per month and P2 costs roughly $9 to $10 per user per month, with a Microsoft Entra Suite bundle around $12 per user per month.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Is Entra ID included in Microsoft 365?$q$, $q$Microsoft 365 E3 includes Entra ID P1 and Microsoft 365 E5 includes Entra ID P2, so many enterprise customers already have a paid tier through existing licensing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$What are the main alternatives to Microsoft Entra ID?$q$, $q$The main competitors are Okta, Ping Identity, and Google Cloud Identity.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Enterprise single sign-on$q$, $q$IT teams deploy Entra ID to give employees one login across Microsoft 365, Azure, and third-party SaaS apps instead of separate credentials per app.$q$, $q$IT and security teams at mid-size to large organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Zero-trust access control$q$, $q$Security teams use Conditional Access and Identity Protection to enforce risk-based, device-aware access policies across the organization.$q$, $q$Security and compliance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Privileged access governance$q$, $q$Organizations use Privileged Identity Management to grant admin rights only when needed rather than maintaining standing administrative access.$q$, $q$IT administrators managing sensitive systems$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 500,000 directory objects","SSO for up to 10 cloud apps per user","Self-service password change","B2B collaboration up to 50,000 MAU","Basic audit and sign-in reports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Entra ID P1$q$, $q$$6-$7/user/month$q$, $q$Monthly$q$, NULL, $q$["Conditional Access","Group-based access management","Hybrid self-service password reset","Advanced usage reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Entra ID P2$q$, $q$$9-$10/user/month$q$, $q$Monthly$q$, NULL, $q$["Everything in P1","Identity Protection","Privileged Identity Management (PIM)","Access reviews"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$Microsoft Entra Suite$q$, $q$~$12/user/month$q$, $q$Monthly$q$, NULL, $q$["Everything in P2","Additional security add-ons across the Entra portfolio"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Entra ID is Microsoft's cloud identity and access management platform, formerly known as Azure Active Directory. Microsoft announced the rename on July 11, 2023, rolling it out across products through the rest of that year, while stating explicitly that pricing and functionality were unchanged, only the name.$q$, $q$Entra ID acts as the centralized identity layer for Microsoft 365, Azure, and thousands of third-party SaaS applications, authenticating users once and enforcing access policies everywhere through single sign-on rather than requiring separate credentials per app.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities available even on the free tier include single sign-on for up to 10 cloud apps per user, multi-factor authentication, self-service password change, and B2B collaboration for inviting external partners into a tenant. Paid tiers unlock Conditional Access, which grants or restricts access based on signals like device compliance, location, and calculated risk.$q$, $q$Entra ID P2 adds Identity Protection, which uses machine learning to flag risky sign-ins and accounts and feeds those risk scores into Conditional Access policies, plus Privileged Identity Management (PIM) for just-in-time elevation of administrative access instead of standing admin rights, and access reviews for periodic recertification of who has access to sensitive resources.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71439181-0154-4626-9efe-059864fd8420', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Entra ID Free is included with any Microsoft online business service and covers up to 500,000 directory objects, SSO for up to 10 cloud apps per user, and basic sign-in reports. Entra ID P1 (roughly $6 to $7/user/month) adds Conditional Access and hybrid self-service password reset, while Entra ID P2 (roughly $9 to $10/user/month) adds Identity Protection and Privileged Identity Management.$q$, $q$Microsoft Entra Suite bundles P2 with additional security add-ons for around $12/user/month. Many enterprises already have P1 or P2 included through Microsoft 365 E3 or E5 licensing respectively, since Entra ID P1 is bundled into E3 and P2 is bundled into E5.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Survey and form builder$q$, $q$Create forms with up to eight question types including choice, text, rating, and ranking questions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Conditional branching$q$, $q$Show or hide sections of a form based on how a respondent answered a previous question.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Automatic quiz grading$q$, $q$Quizzes can be graded automatically, assigned due dates, and pushed directly into Teams assignments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Excel response export$q$, $q$Responses flow directly into Excel for analysis, charting, and further processing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Teams integration$q$, $q$Forms and quizzes can be shared, assigned, and completed directly inside Microsoft Teams channels.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Power Automate triggers$q$, $q$New form responses can trigger automated workflows, such as notifications or record updates, through Power Automate.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$SharePoint embedding$q$, $q$Forms can be embedded directly into SharePoint intranet sites.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$GDPR-compliant data handling$q$, $q$Forms achieved GDPR compliance in 2017, supporting deployment for European organizations and users.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Included at no extra cost with any Microsoft 365 or Office 365 subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Deep native integration with Excel, Teams, SharePoint, and Power Automate$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Automatic quiz grading makes it a strong fit for schools already on Microsoft 365$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Simple, low-friction interface for building quick surveys and forms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$GDPR-compliant, supporting deployment across European organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Free personal plan is capped at 200 responses per form$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Limited to eight question types compared to more flexible dedicated survey tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$No custom branding on lower-tier plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$No advanced analytics, open-text sentiment analysis, or offline data collection$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$No dedicated customer support channel$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Is Microsoft Forms free?$q$, $q$Yes, a free personal plan exists with a 200-response-per-form cap; higher response limits require a Microsoft 365 Personal, Business, or Education subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$When did Microsoft Forms launch?$q$, $q$Forms was first released on June 20, 2016 for Office 365 Education, with a broader commercial public preview following in 2017.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Can Microsoft Forms grade quizzes automatically?$q$, $q$Yes, quizzes can be automatically graded, assigned due dates, and pushed directly into Microsoft Teams assignments.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Does Microsoft Forms integrate with Power Automate?$q$, $q$Yes, new form responses can trigger Power Automate workflows, a capability added in 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$How many responses can Microsoft Forms handle?$q$, $q$The free personal plan caps at 200 responses per form, Microsoft 365 Personal raises it to about 1,000, and Microsoft 365 Apps for Business or Education plans support up to 5,000,000 responses.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$What are the main alternatives to Microsoft Forms?$q$, $q$The main competitors are Google Forms, Typeform, SurveyMonkey, and Jotform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Classroom quizzes and assessments$q$, $q$Teachers create auto-graded quizzes that push directly into Teams assignments, replacing the need for a separate quiz tool.$q$, $q$Educators and schools on Microsoft 365 Education$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Employee and event feedback surveys$q$, $q$Organizations collect feedback or event registrations with responses flowing directly into Excel for reporting.$q$, $q$HR teams and internal event organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Automated workflow triggers$q$, $q$Teams use form submissions to kick off Power Automate workflows, such as approval routing or SharePoint list updates.$q$, $q$Operations and IT teams building lightweight automations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Free Personal$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 200 responses per form","Up to 400 surveys","Up to 200 questions per form","Excel export"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Microsoft 365 Personal$q$, $q$~$6-$10/month$q$, $q$Monthly$q$, NULL, $q$["Up to ~1,000 responses per form","Full Microsoft 365 app access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$Microsoft 365 Apps for Business / Education$q$, $q$Included in Microsoft 365 business/education licensing$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 5,000,000 responses per form","Teams and SharePoint integration","Power Automate integration"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Forms is a survey, quiz, and form-building tool included with Microsoft 365 and Office 365. It launched on June 20, 2016 for Office 365 Education, with a broader commercial preview following in 2017, and has since become a standard tool for lightweight data collection inside organizations already using Microsoft's productivity suite.$q$, $q$Forms is built to be simple: users create a form with up to eight question types, share a link, and watch responses populate automatically. Its main value is not competing on advanced survey logic but on being free and pre-integrated for anyone already inside the Microsoft 365 ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Forms supports conditional branching, showing or hiding sections based on how a respondent answered a prior question, which covers most common survey design needs without requiring a more complex tool. Quizzes can be automatically graded, assigned due dates, and pushed directly into Teams assignments, a feature heavily used in education settings.$q$, $q$Native integrations set Forms apart from many free competitors: responses can flow straight into Excel for analysis, forms can be shared or assigned inside Teams channels, forms can be embedded in SharePoint sites, and new responses can trigger automated workflows through Power Automate, such as sending a Teams notification or updating a spreadsheet.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9b2788d-5b29-41aa-b1ae-b0abdc9d06ec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The free personal plan is capped at 200 responses per form, 400 surveys, and 200 questions per form, which suits casual or small-scale use. A Microsoft 365 Personal subscription raises the response limit to roughly 1,000 per form.$q$, $q$Organizations on Microsoft 365 Apps for Business or Microsoft 365 Education plans get support for up to 5,000,000 responses per form, which removes practical limits for most business, school, and event-registration use cases, since Forms itself has no separate standalone price and is bundled into existing Microsoft 365 licensing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Canvas apps$q$, $q$A visual drag-and-drop designer for building fully custom app layouts and logic.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Model-driven apps$q$, $q$Automatically generates a complete app from a data model defined in Microsoft Dataverse.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Dataverse integration$q$, $q$A shared, governed data platform that Power Apps, Power Automate, and Power BI can all draw from.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Hundreds of data connectors$q$, $q$Pre-built connectors for SharePoint, SQL Server, Excel, Salesforce, SAP, and hundreds of other systems.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$AI Builder$q$, $q$Adds pre-built AI models, such as form processing and object detection, into an app without data science expertise.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Power Pages$q$, $q$Builds external-facing, low-code websites on the same Dataverse backend used by internal apps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Custom connectors$q$, $q$Extends Power Apps to connect with internal or third-party APIs not covered by standard connectors.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Managed environments and governance$q$, $q$Admin tooling for applying data loss prevention policies and monitoring app usage across an organization.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Deep integration with Microsoft 365, Power Automate, Power BI, and Dataverse$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Supports both citizen developers and professional developers on the same platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Hundreds of pre-built connectors reduce custom integration work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$AI Builder adds AI capabilities without requiring data science skills$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Pay-As-You-Go option controls cost for pilots and occasional users$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Removal of the cheaper Per App plan in January 2026 raised the effective entry cost for many customers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Premium connectors and Dataverse usage can add unexpected licensing costs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Requires a separate underlying Microsoft 365 license for most production users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Steeper learning curve for model-driven apps and Dataverse data modeling than pure canvas apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Governance and environment management require dedicated IT/admin effort at scale$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$How much does Microsoft Power Apps cost?$q$, $q$Power Apps Premium costs $20 per user per month billed annually, with reduced volume pricing around $12/user/month for enterprise deployments of 2,000+ seats; a Pay-As-You-Go plan charges roughly $10 per active user per app per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Is there a free version of Power Apps?$q$, $q$Yes, the Power Apps Developer Plan is free for building and testing apps, but it is intended for learning and prototyping, not production use.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$What is the difference between canvas apps and model-driven apps?$q$, $q$Canvas apps use a visual drag-and-drop designer for full layout control, while model-driven apps are generated automatically from a data model defined in Microsoft Dataverse.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$When did Power Apps launch?$q$, $q$Power Apps became generally available in November 2016 as part of the newly formed Microsoft Power Platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Do I still need a Microsoft 365 license to use Power Apps?$q$, $q$Yes, most production users need an underlying Microsoft 365 license in addition to their Power Apps license.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$What happened to the Power Apps Per App plan?$q$, $q$Microsoft removed the Per App plan from its licensing guide in January 2026, making Premium (per user) and Pay-As-You-Go the two primary paths for most customers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Departmental process automation$q$, $q$Business users build custom apps to digitize processes like inspections, approvals, or inventory tracking without a full development team.$q$, $q$Citizen developers and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Line-of-business application development$q$, $q$IT teams build governed, enterprise-grade apps connected to Dataverse and internal systems for company-wide use.$q$, $q$IT departments and professional developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$External-facing portals$q$, $q$Organizations use Power Pages to build customer or partner-facing websites tied to the same backend data as internal apps.$q$, $q$Businesses needing external self-service portals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Developer Plan$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Build and test apps for learning and prototyping","Not licensed for production use"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Power Apps Premium$q$, $q$$20/user/month$q$, $q$Annual commitment$q$, NULL, $q$["Unlimited apps and Power Pages sites","Premium connectors","Dataverse access","500 AI Builder credits/user/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$Pay-As-You-Go$q$, $q$~$10/active user/app/month$q$, $q$Monthly, usage-based$q$, NULL, $q$["Billed only for users who open an app in a given month","Suited to pilots and occasional/external users"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Power Apps is a low-code platform for building custom business applications, generally available since November 2016 as one of the founding products of Microsoft's Power Platform. It lets both non-technical business users and professional developers build apps with a fraction of the hand-written code required by traditional development.$q$, $q$Power Apps offers two primary app-building approaches: canvas apps, a visual drag-and-drop designer for full control over layout, and model-driven apps, which generate a complete app automatically from a data model defined in Microsoft Dataverse.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Apps can connect to hundreds of standard and premium data connectors including SharePoint, SQL Server, Excel, Salesforce, and SAP, and can be extended with custom connectors for internal or third-party APIs. AI Builder adds pre-built AI capabilities, such as form processing and object detection, into an app without requiring data science skills.$q$, $q$Power Pages extends the platform to external-facing, low-code websites built on the same Dataverse backend used by internal apps. Managed environments and governance tooling let IT admins apply data loss prevention policies and monitor app usage across an organization at scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f60ec8fa-b75a-462e-84f1-bc0d2d866e63', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Microsoft phased out the older Per App plan from its licensing guide in January 2026, leaving Power Apps Premium ($20/user/month, billed annually) as the main per-user path, which includes unlimited apps, Dataverse, premium connectors, and 500 AI Builder credits per user per month. Large enterprise deployments of 2,000+ seats can access reduced volume pricing around $12/user/month.$q$, $q$A Pay-As-You-Go plan (roughly $10 per active user per app per month) charges only for users who actually open an app in a given month, which fits pilots or external/seasonal access. A free Developer Plan supports individual learning and prototyping but is not licensed for production use, and any production user still needs an underlying Microsoft 365 license.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Cloud flows$q$, $q$Automated, scheduled, or manually triggered workflows connecting cloud apps and services.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Desktop flows (RPA)$q$, $q$Record-and-replay automation of actions across desktop and legacy applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Unattended bots$q$, $q$Bots that run automatically on a schedule without a supervising human user, via the Process or Hosted Process plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Business process flows$q$, $q$Guided, multi-step processes that enforce a consistent workflow across a team.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$AI Builder integration$q$, $q$Adds pre-built AI models, such as document processing, into automated flows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Process Mining$q$, $q$Analyzes how business processes actually run in practice to surface automation opportunities.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Standard and premium connectors$q$, $q$Hundreds of connectors for Microsoft and third-party apps, split between included standard connectors and licensed premium connectors.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Power Platform integration$q$, $q$Flows can be triggered by or feed into Power Apps and Power BI within the same platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Basic cloud automation is included with any Microsoft 365 subscription at no extra cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Covers both simple cloud workflows and enterprise-grade unattended RPA on one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Deep integration with Power Apps, Power BI, and Microsoft 365 apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$AI Builder adds AI capabilities to flows without separate data science tooling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Process Mining helps identify which processes are worth automating before building flows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Premium connectors require a separate $15/user/month license even for occasional use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Unattended RPA bots are expensive at $150-$215 per bot per month$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Process Mining add-on is costly at $5,000 per tenant per month$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Licensing model (per-user, per-flow, per-bot) can be complex to plan for at scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Desktop flow reliability can be sensitive to UI changes in the applications being automated$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Is Microsoft Power Automate free with Microsoft 365?$q$, $q$Basic cloud flows using standard connectors (Outlook, SharePoint, Teams, OneDrive, Excel, Planner) are included with Microsoft 365 at no extra cost; premium connectors require a separate Premium license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$What was Power Automate called before?$q$, $q$It launched as Microsoft Flow in 2016 and was renamed Power Automate on November 4, 2019 at Microsoft Ignite.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$How much does Power Automate Premium cost?$q$, $q$Power Automate Premium costs $15 per user per month and includes unlimited cloud flows, attended desktop flows, and 5,000 AI Builder credits.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$What is the difference between attended and unattended RPA in Power Automate?$q$, $q$Attended automation runs alongside a human user under the Premium plan, while unattended automation runs bots automatically without supervision and requires the Process plan ($150/bot/month) or Hosted Process plan ($215/bot/month).$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$What is Process Mining in Power Automate?$q$, $q$Process Mining analyzes how business processes actually execute in practice, helping identify automation opportunities; it's available only as a Premium add-on for $5,000 per tenant per month.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$What are the main alternatives to Power Automate?$q$, $q$The main competitors are Zapier, UiPath, Automation Anywhere, and Make (formerly Integromat).$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Everyday personal and team automation$q$, $q$Microsoft 365 users automate routine tasks like saving email attachments to OneDrive or notifying a Teams channel when a form is submitted.$q$, $q$Individual Microsoft 365 users and small teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Enterprise robotic process automation$q$, $q$Organizations replace manual, repetitive back-office processes with unattended RPA bots running on a schedule.$q$, $q$Enterprise automation and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Cross-system business process orchestration$q$, $q$IT teams connect Salesforce, SAP, and other premium-connector systems into automated, multi-step business processes.$q$, $q$IT and business process teams at mid-size to large organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Included with Microsoft 365$q$, $q$Included$q$, $q$N/A$q$, NULL, $q$["Cloud flows using standard connectors only","Covers Outlook, SharePoint, Teams, OneDrive, Excel, Forms, Planner"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Power Automate Premium$q$, $q$$15/user/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited cloud flows","Attended desktop flows","5,000 AI Builder credits","250 MB database / 2 GB file storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Process (Unattended RPA)$q$, $q$$150/bot/month$q$, $q$Monthly$q$, NULL, $q$["Unattended bot automation"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$Hosted Process$q$, $q$$215/bot/month$q$, $q$Monthly$q$, NULL, $q$["Unattended bot automation on Microsoft-hosted infrastructure"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Power Automate is a workflow automation and RPA platform that connects apps and automates repetitive tasks. It began as Microsoft Flow, generally available from October 2016, and was rebranded to Power Automate on November 4, 2019, a change that coincided with expanding the product beyond cloud workflows into desktop RPA and virtual agents.$q$, $q$The platform spans three main automation types: cloud flows for connecting online apps and services, desktop flows for RPA-style automation of desktop and legacy applications, and business process flows for enforcing consistent, guided multi-step processes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Any Microsoft 365 user can build cloud flows using standard connectors for apps like Outlook, SharePoint, Teams, OneDrive, Excel, and Planner without an extra license. Flows built with premium connectors, such as Salesforce or SAP, require a Power Automate Premium license.$q$, $q$For robotic process automation, desktop flows can run in attended mode (triggered by and running alongside a human user) under the Premium plan, or in unattended mode via the Process or Hosted Process plans, where bots run automatically without a supervising user. Process Mining, available as a Premium add-on, analyzes how business processes actually execute in practice to identify automation opportunities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Power Automate Premium costs $15 per user per month and includes unlimited cloud flows, attended desktop flows, 5,000 AI Builder credits, and cloud storage. Unattended RPA requires the Process plan at $150 per bot per month, or Hosted Process at $215 per bot per month for Microsoft-hosted bot infrastructure.$q$, $q$A Per Flow plan, around $500 per month for 5 flows, licenses specific organization-wide flows rather than individual users. Process Mining is an additional add-on available only on the Premium plan, priced at $5,000 per tenant per month billed annually.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11ea99d1-4f63-4f6b-9533-0e1448c3d8f5', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Desktop$q$, $q$A free Windows application for connecting to data, modeling relationships, and building report visuals.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$DAX formula language$q$, $q$Data Analysis Expressions let users build custom calculations and measures within data models.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Service$q$, $q$A cloud platform for publishing, sharing, and scheduling refreshes of finished reports and dashboards.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Hundreds of data connectors$q$, $q$Connects to Excel, SQL databases, Salesforce, Google Analytics, and hundreds of other data sources.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Paginated reports$q$, $q$Pixel-perfect, print-ready report formats available on Premium tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Deployment pipelines$q$, $q$Manage report versions across development, test, and production environments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Mobile apps$q$, $q$Native mobile apps for viewing dashboards and reports on the go.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$AI-powered analytics$q$, $q$Built-in AI features for natural-language querying and automated insights, expanded on Premium tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Desktop is free for individual report building$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Tight integration with Excel and the broader Microsoft 365/Azure ecosystem$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Used by over 350,000 organizations, indicating a mature ecosystem and community$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Scales from a single Pro seat to enterprise-wide capacity or Fabric licensing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Frequent feature updates, with over 1,500 shipped since its 2015 launch$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Pro and Premium Per User prices increased significantly in April 2025 ($10 to $14 and $20 to $24)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Sharing and collaborating on reports requires a paid Pro or Premium license even for viewers in some configurations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Capacity-based Premium licensing is being phased toward Fabric, adding complexity for long-term planning$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$DAX and data modeling have a real learning curve for non-technical users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Large-scale enterprise analytics increasingly pushes customers toward the pricier Fabric platform$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Is Power BI free?$q$, $q$Power BI Desktop, the report-building application, is free; sharing and collaborating on published reports inside an organization requires a paid Pro or Premium Per User license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$How much does Power BI Pro cost?$q$, $q$Power BI Pro costs $14 per user per month paid annually, following an April 2025 increase from the previous $10 price.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$What is the difference between Power BI Pro and Premium Per User?$q$, $q$Premium Per User ($24/user/month) raises the dataset size limit to 100 GB versus Pro's 1 GB, increases daily refreshes to 48 from 8, and adds paginated reports and advanced AI features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$When did Power BI launch?$q$, $q$Power BI began as Power BI for Office 365 in 2013, with the standalone product most people use today launching on July 24, 2015.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$What is Microsoft Fabric's relationship to Power BI?$q$, $q$Microsoft Fabric is Microsoft's newer, broader analytics platform, and Power BI capacity licensing is gradually being shifted toward Fabric capacity SKUs at renewal for large-scale deployments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$What are the main alternatives to Power BI?$q$, $q$The main competitors are Tableau, Google Looker, and Qlik Sense.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Business reporting and dashboards$q$, $q$Analysts build interactive dashboards that let stakeholders explore sales, marketing, or operations data without needing a dedicated analyst for every question.$q$, $q$Business analysts and department leads$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Enterprise data governance and self-service BI$q$, $q$IT and data platform teams create governed datasets that business users can safely build their own reports on top of.$q$, $q$Data platform and IT teams at large organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Excel-integrated financial and operational analysis$q$, $q$Finance and operations teams already working in Excel extend their analysis into interactive Power BI reports using the same underlying data.$q$, $q$Finance and operations analysts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Desktop$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Build and model reports locally","Connect to hundreds of data sources","No sharing/publishing to the cloud service"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Pro$q$, $q$$14/user/month$q$, $q$Annual$q$, NULL, $q$["Publish and share reports via Power BI Service","Standard refresh rates","Collaboration in app workspaces"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$Power BI Premium Per User$q$, $q$$24/user/month$q$, $q$Annual$q$, NULL, $q$["100 GB dataset size limit","Up to 48 daily refreshes","Paginated reports","Deployment pipelines","Advanced AI features"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Power BI is a business intelligence platform for building interactive reports and dashboards. It began as Power BI for Office 365, previewed in July 2013, before the standalone product most people know today, including Power BI Desktop, the Power BI Service, and mobile apps, launched on July 24, 2015.$q$, $q$Power BI connects to hundreds of data sources and lets users model relationships and build visuals using DAX, Microsoft's formula language for data analysis. As of 2026, it is used by over 350,000 organizations, reflecting its position as one of the most widely adopted BI platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Power BI Desktop, a free Windows application, is where most report-building happens: connecting to data sources, modeling relationships between tables, and designing report visuals. Finished reports publish to the Power BI Service, the cloud platform used to share dashboards, schedule data refreshes, and collaborate with colleagues.$q$, $q$Higher tiers unlock larger dataset limits, more frequent data refreshes, paginated (pixel-perfect, print-ready) reports, deployment pipelines for managing report versions across development and production, and advanced AI-powered analytics features built into the report canvas.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae91efd-338e-4ef0-9f0b-3f2a51548062', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Power BI Desktop is free for building reports individually. Power BI Pro costs $14 per user per month (paid annually), following an April 2025 price increase from $10, and is required for sharing and collaborating on reports inside an organization.$q$, $q$Power BI Premium Per User costs $24 per user per month, up from $20, and raises the dataset size limit to 100 GB, increases refreshes to 48 per day, and unlocks paginated reports and advanced AI features. Larger organizations can also license capacity-based Premium or Fabric SKUs, with Microsoft gradually shifting customers toward Fabric capacity at renewal as its long-term large-scale analytics offering.$q$]::text[], 2);
